+    const { state, calls } = buildRuntime();
+
+    await currentProps?.onChange({ mode: "video", slides: true });
+
+    expect(fetchSpy).toHaveBeenCalledOnce();
+    expect(calls.showSlideNotice).toHaveBeenCalledWith(
